const { createWriteStream } = require("fs");
const { execSync, execFile } = require("child_process");
const path = require('path');


function copy(oldPath , newPath){
  return new Promise((resolve)=>{
    let source = createReadStream(oldPath);
    const destination = createWriteStream(newPath);
    source.pipe(destination)
        .on('finish', () => resolve());
});}
  
async function main(){
    try{
        const installCommand = execSync(`npm i`);
        await copy(path.resolve(__dirname,'../../packages/package-json'), path.resolve(__dirname,'../../package.json'));
        console.log(installCommand);
    }catch (e){

        console.error(e) ;
    }
}